      'svc.rep.title': 'Inteligencia Defendible. Entrega Decisiva.',
      'svc.rep.sub': 'Todos los informes comienzan con un resumen ejecutivo y evaluación de riesgos, seguidos de hallazgos detallados organizados por dominio de inteligencia.',
      'svc.rep.basic.num': 'Básico',
      'svc.rep.basic.name': 'Informe de Base',
