      'about.sector.re': 'Bienes Raíces y Desarrollo',
      'about.sector.gov': 'Entidades Gubernamentales',
      'about.sector.energy': 'Energía y Recursos Naturales',
      'about.sector.pharma': 'Farmacéutica y Salud',
      'about.sector.infra': 'Infraestructura y Construcción',
      'about.sector.tech': 'Tecnología y Telecomunicaciones',
      'about.cov.eyebrow': 'Cobertura Geográfica',
      'about.cov.title': 'Dónde Operamos',
      'about.cov.sub': 'ISSLA Risk cubre Norteamérica, el Caribe y Sudamérica — con profundidad especializada en los mercados donde la opacidad, el riesgo político y la complejidad jurisdiccional son más altos.',
      'about.cov.na.title': 'Norteamérica',
      'about.cov.na.desc': 'Cobertura completa de Estados Unidos y Canadá, incluyendo análisis corporativos transfronterizos, investigación de cumplimiento regulatorio y vetting de socios previo a transacciones en todas las principales jurisdicciones.',
      'about.cov.carib.title': 'El Caribe',
      'about.cov.carib.desc': 'Profundidad especializada en jurisdicciones offshore del Caribe, registros corporativos de estados insulares y centros financieros regionales — donde la opacidad de titularidad real y la complejidad de estructuras societarias exigen conocimiento local experimentado.',
      'about.cov.sa.title': 'Sudamérica',
      'about.cov.sa.desc': 'Cobertura integral de los mercados sudamericanos, con expertise particular en Colombia, Brasil, Argentina y Perú — jurisdicciones con alta actividad de inversión junto con elevado riesgo político y regulatorio.',
      'about.off.eyebrow': 'Nuestras Oficinas',
