      /* --- FAQ --- */
      'faq.hero.eyebrow': 'Preguntas Frecuentes',
      'faq.hero.title': 'Preguntas y Respuestas',
      'faq.hero.sub': 'Todo lo que necesita saber sobre los servicios, el proceso y el modo de trabajo de ISSLA Risk. Si su pregunta no tiene respuesta aquí, contáctenos directamente.',
      'faq.cat.about': 'Sobre ISSLA Risk',
      'faq.cat.services': 'Nuestros Servicios',
      'faq.cat.process': 'Proceso y Metodología',
      'faq.cat.confidentiality': 'Confidencialidad y Seguridad',
